mapper.select:
/* TM_ECS_INTN_USR_ATHR_RQST_Dao_retrieveUsrAthrRqst */ SELECT A.RQST_SEQ, A.USR_ID, (SELECT KORNAME FROM HRM.vm_hr01601 WHERE EMPNO = A.USR_ID ) AS USR_NM, A.ATHR_ID, A.PRGSTS_CD, A.APPLC_STRT_DE, A.APPLC_END_DE, UNIF_RQST_SEQ, TO_CHAR(A.RQST_DT, 'YYYYMMDDHH24MISS') AS RQST_DT, APPRVR_ID, (SELECT KORNAME FROM HRM.vm_hr01601 WHERE EMPNO = A.APPRVR_ID ) AS APPRVR_NM, TO_CHAR(A.APRV_DT, 'YYYYMMDDHH24MISS') AS APRV_DT, TO_CHAR(A.CANCL_DT, 'YYYYMMDDHH24MISS') AS CANCL_DT FROM tm_ecs_intn_usr_athr_rqst A, tm_ecs_intn_athr B, tm_ecs_intn_usr_athr C WHERE 1 = 1 AND A.ATHR_ID = B.ATHR_ID AND A.ATHR_ID = C.ATHR_ID(+) AND A.USR_ID = C.USR_ID(+)
AND A.USR_ID = #{usrId}
/*권한명으로 검색시*/ AND B.ATHR_ID = #{athrId}

/* TM_ECS_INTN_USR_ATHR_RQST_Dao_retrieveUsrAthrRqstAdmin */ SELECT A.RQST_SEQ, A.USR_ID, (SELECT KORNAME FROM HRM.vm_hr01601 WHERE EMPNO = A.USR_ID ) AS USR_NM, A.ATHR_ID, A.PRGSTS_CD, A.APPLC_STRT_DE, A.APPLC_END_DE, UNIF_RQST_SEQ, TO_CHAR(A.RQST_DT, 'YYYYMMDDHH24MISS') AS RQST_DT, A.APPRVR_ID, (SELECT KORNAME FROM HRM.vm_hr01601 WHERE EMPNO = A.APPRVR_ID ) AS APPRVR_NM, TO_CHAR(A.APRV_DT, 'YYYYMMDDHH24MISS') AS APRV_DT, TO_CHAR(A.CANCL_DT, 'YYYYMMDDHH24MISS') AS CANCL_DT FROM tm_ecs_intn_usr_athr_rqst A, tm_ecs_intn_athr B, tm_ecs_intn_usr_athr C WHERE 1 = 1 AND A.ATHR_ID = B.ATHR_ID AND A.ATHR_ID = C.ATHR_ID(+) AND A.USR_ID = C.USR_ID(+)
/* 관리자일 경우 자신의 시스템구분에 맞는 권한만 조회 */ AND B.INTN_SYS_DIV_CD = #{intnSysDivCd}
/* 업무구분에 맞는 권한만 조회 */ AND A.ATHR_ID LIKE #{intnSysDivCd}|| #{intnBiznDivCd}||'%'
/* 특정 사용자만 조회 */ AND A.USR_ID = #{usrId}
/* 권한명으로 검색시 */ AND A.ATHR_ID = #{athrId}
/* 상태로 검색시 */ AND A.PRGSTS_CD = #{prgstsCd}
/*신청 일자(기간)으로 조회할 경우*/ AND TO_CHAR(A.RQST_DT, 'YYYYMMDDHH24MISS' ) BETWEEN #{strtDt} || '000000' AND #{endDt} || '235959'

mapper.delete:
/* TM_ECS_INTN_USR_ATHR_RQST_Dao_deleteUsrAthrRqst */
DELETE FROM
	tm_ecs_intn_usr_athr_rqst
WHERE
	RQST_SEQ = #{rqstSeq}
	AND PRGSTS_CD = 'RO'
